46→    private fun add(command: ViewerCommand, preferences: SharedPreferences) {
47→        val bindings: MutableList<MappableBinding> = fromPreference(preferences, command)
48→        for (b in bindings) {
49→            if (!b.isKey) {
50→                continue
51→            }
52→            mKeyMap[b] = command
53→        }
54→    }
