            // Legacy defaults that previously lived on FLIP_OR_ANSWER_RECOMMENDED
            private val legacyRecommendedDefaultBindings: List<MappableBinding> = listOf(
                MappableBinding(keyCode(KeyEvent.KEYCODE_DPAD_CENTER), MappableBinding.Screen.Reviewer(CardSide.BOTH)),
                MappableBinding(keyCode(KeyEvent.KEYCODE_SPACE), MappableBinding.Screen.Reviewer(CardSide.ANSWER)),
                MappableBinding(keyCode(KeyEvent.KEYCODE_ENTER), MappableBinding.Screen.Reviewer(CardSide.ANSWER)),
                MappableBinding(keyCode(KeyEvent.KEYCODE_NUMPAD_ENTER), MappableBinding.Screen.Reviewer(CardSide.ANSWER))
            )

            override fun upgrade(preferences: SharedPreferences) {
                migrateBindings(
                    preferences,
                    oldPreferenceKey = "binding_FLIP_OR_ANSWER_RECOMMENDED",
                    newCommand = ViewerCommand.FLIP_OR_ANSWER_EASE3,
                    addLegacyDefaultsIfOldMissing = legacyRecommendedDefaultBindings
                )
                migrateBindings(
                    preferences,
                    oldPreferenceKey = "binding_FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED",
                    newCommand = ViewerCommand.FLIP_OR_ANSWER_EASE4
                )
            }

            private fun migrateBindings(
                preferences: SharedPreferences,
                oldPreferenceKey: String,
                newCommand: ViewerCommand,
                addLegacyDefaultsIfOldMissing: List<MappableBinding> = emptyList()
            ) {
                if (preferences.contains(oldPreferenceKey)) {
                    val oldValue = preferences.getString(oldPreferenceKey, null)
                    val oldBindings = MappableBinding.fromPreferenceString(oldValue)

                    // Preserve existing bindings on the target command; append migrated bindings.
                    for (binding in oldBindings) {
                        newCommand.addBindingAtEnd(preferences, binding)
                    }

                    preferences.edit { remove(oldPreferenceKey) }
                    return
                }

                // If the user customized the target command, they won't get updated defaults via ViewerCommand.defaultValue.
                // Add the legacy defaults in that case to preserve pre-upgrade behavior.
                if (addLegacyDefaultsIfOldMissing.isNotEmpty() && preferences.contains(newCommand.preferenceKey)) {
                    for (binding in addLegacyDefaultsIfOldMissing) {
                        newCommand.addBindingAtEnd(preferences, binding)
                    }
                }
            }
        }"}

