        internal class UpgradeRemovedRecommendedAnswerCommands : PreferenceUpgrade(12) {
            override fun upgrade(preferences: SharedPreferences) {
                migrateBindings(preferences, "binding_FLIP_OR_ANSWER_RECOMMENDED", ViewerCommand.FLIP_OR_ANSWER_EASE3)
                migrateBindings(preferences, "binding_FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED", ViewerCommand.FLIP_OR_ANSWER_EASE4)
            }

            private fun migrateBindings(preferences: SharedPreferences, oldPreferenceKey: String, newCommand: ViewerCommand) {
                if (!preferences.contains(oldPreferenceKey)) {
                    return
                }

                val oldValue = preferences.getString(oldPreferenceKey, null)
                val oldBindings = MappableBinding.fromPreferenceString(oldValue)

                // Preserve existing bindings on the target command; append migrated bindings.
                for (binding in oldBindings) {
                    newCommand.addBindingAtEnd(preferences, binding)
                }

                preferences.edit { remove(oldPreferenceKey) }
            }
        }
    }
